import{_ as o,o as a,c as t,ai as s}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"Health Checks","description":"","frontmatter":{"summary":"Health check steps for channel connectivity","read_when":["Diagnosing WhatsApp channel health"],"title":"Health Checks"},"headers":[],"relativePath":"gateway/health.md","filePath":"gateway/health.md","lastUpdated":null}'),n={name:"gateway/health.md"};function l(c,e,i,d,h,r){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="health-checks-cli" tabindex="-1"><a class="header-anchor" href="#health-checks-cli">#</a> Health Checks (CLI)</h1><p>Short guide to verify channel connectivity without guessing.</p><h2 id="quick-checks" tabindex="-1"><a class="header-anchor" href="#quick-checks">#</a> Quick checks</h2><ul><li><code>opensoul status</code> — local summary: gateway reachability/mode, update hint, linked channel auth age, sessions + recent activity.</li><li><code>opensoul status --all</code> — full local diagnosis (read-only, color, safe to paste for debugging).</li><li><code>opensoul status --deep</code> — also probes the running Gateway (per-channel probes when supported).</li><li><code>opensoul health --json</code> — asks the running Gateway for a full health snapshot (WS-only; no direct Baileys socket).</li><li>Send <code>/status</code> as a standalone message in WhatsApp/WebChat to get a status reply without invoking the agent.</li><li>Logs: tail <code>/tmp/opensoul/opensoul-*.log</code> and filter for <code>web-heartbeat</code>, <code>web-reconnect</code>, <code>web-auto-reply</code>, <code>web-inbound</code>.</li></ul><h2 id="deep-diagnostics" tabindex="-1"><a class="header-anchor" href="#deep-diagnostics">#</a> Deep diagnostics</h2><ul><li>Creds on disk: <code>ls -l ~/.opensoul/credentials/whatsapp/&lt;accountId&gt;/creds.json</code> (mtime should be recent).</li><li>Session store: <code>ls -l ~/.opensoul/agents/&lt;agentId&gt;/sessions/sessions.json</code> (path can be overridden in config). Count and recent recipients are surfaced via <code>status</code>.</li><li>Relink flow: <code>opensoul channels logout &amp;&amp; opensoul channels login --verbose</code> when status codes 409–515 or <code>loggedOut</code> appear in logs. (Note: the QR login flow auto-restarts once for status 515 after pairing.)</li></ul><h2 id="when-something-fails" tabindex="-1"><a class="header-anchor" href="#when-something-fails">#</a> When something fails</h2><ul><li><code>logged out</code> or status 409–515 → relink with <code>opensoul channels logout</code> then <code>opensoul channels login</code>.</li><li>Gateway unreachable → start it: <code>opensoul gateway --port 18789</code> (use <code>--force</code> if the port is busy).</li><li>No inbound messages → confirm linked phone is online and the sender is allowed (<code>channels.whatsapp.allowFrom</code>); for group chats, ensure allowlist + mention rules match (<code>channels.whatsapp.groups</code>, <code>agents.list[].groupChat.mentionPatterns</code>).</li></ul><h2 id="dedicated-health-command" tabindex="-1"><a class="header-anchor" href="#dedicated-health-command">#</a> Dedicated &quot;health&quot; command</h2><p><code>opensoul health --json</code> asks the running Gateway for its health snapshot (no direct channel sockets from the CLI). It reports linked creds/auth age when available, per-channel probe summaries, session-store summary, and a probe duration. It exits non-zero if the Gateway is unreachable or the probe fails/timeouts. Use <code>--timeout &lt;ms&gt;</code> to override the 10s default.</p>',10)])])}const g=o(n,[["render",l]]);export{p as __pageData,g as default};
